package com.cho2hand.marketplace.service.impl.media;
import com.cho2hand.marketplace.dto.media.*;import com.cho2hand.marketplace.entity.media.*;import com.cho2hand.marketplace.exception.*;import com.cho2hand.marketplace.repository.listing.ListingRepository;import com.cho2hand.marketplace.repository.media.*;import com.cho2hand.marketplace.service.media.MediaService;import com.cho2hand.marketplace.storage.MinioProperties;import io.minio.*;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.web.multipart.MultipartFile;
@Service @Transactional public class MediaServiceImpl implements MediaService{private static final Set<String>TYPES=Set.of("image/jpeg","image/png","image/webp");private final ListingRepository listings;private final MediaAssetRepository media;private final ListingImageRepository images;private final MinioClient minio;private final MinioProperties props;public MediaServiceImpl(ListingRepository l,MediaAssetRepository m,ListingImageRepository i,MinioClient c,MinioProperties p){listings=l;media=m;images=i;minio=c;props=p;}public MediaResponse upload(Long user,Long listing,MultipartFile file){owned(user,listing);if(file.isEmpty()||file.getSize()>15_000_000||!TYPES.contains(file.getContentType()))throw new InvalidMediaException("Only JPEG, PNG, WEBP images up to 15 MB are allowed");if(images.countByIdListingId(listing)>=10)throw new InvalidMediaException("A listing can have at most 10 images");var key="listings/"+listing+"/"+UUID.randomUUID();try{minio.putObject(PutObjectArgs.builder().bucket(props.bucket()).object(key).stream(file.getInputStream(),file.getSize(),-1).contentType(file.getContentType()).build());var asset=new MediaAsset();asset.setOwnerUserId(user);asset.setStorageKey(key);asset.setContentType(file.getContentType());asset.setByteSize(file.getSize());asset=media.save(asset);short order=(short)images.countByIdListingId(listing);images.save(new ListingImage(listing,asset.getId(),order));return response(listing,asset,order);}catch(Exception e){throw new IllegalStateException("Unable to store image",e);}}@Transactional(readOnly=true)public List<MediaResponse> list(Long listing){return images.findByIdListingIdOrderBySortOrderAsc(listing).stream().map(i->response(listing,media.findById(i.getId().getMediaId()).orElseThrow(()->new InvalidMediaException("Image not found")),i.getSortOrder())).toList();}@Transactional(readOnly=true)public MediaContent content(Long listing,Long mediaId){images.findById(new ListingImageId(listing,mediaId)).orElseThrow(()->new InvalidMediaException("Image not found"));var asset=media.findById(mediaId).orElseThrow(()->new InvalidMediaException("Image not found"));try(var stream=minio.getObject(GetObjectArgs.builder().bucket(props.bucket()).object(asset.getStorageKey()).build())){return new MediaContent(stream.readAllBytes(),asset.getContentType());}catch(Exception e){throw new IllegalStateException("Unable to read image",e);}}public void delete(Long user,Long listing,Long mediaId){owned(user,listing);var link=images.findById(new ListingImageId(listing,mediaId)).orElseThrow(()->new InvalidMediaException("Image not found"));var asset=media.findById(mediaId).filter(v->user.equals(v.getOwnerUserId())).orElseThrow(()->new InvalidMediaException("Image not found"));try{minio.removeObject(RemoveObjectArgs.builder().bucket(props.bucket()).object(asset.getStorageKey()).build());images.delete(link);media.delete(asset);}catch(Exception e){throw new IllegalStateException("Unable to delete image",e);}}private void owned(Long user,Long id){var x=listings.findById(id).orElseThrow(()->new ListingNotFoundException(id));if(!user.equals(x.getSellerUserId()))throw new ListingAccessDeniedException();}private MediaResponse response(Long listing,MediaAsset asset,short order){return new MediaResponse(asset.getId(),"/api/v1/listings/"+listing+"/images/"+asset.getId()+"/content",asset.getContentType(),asset.getByteSize(),order);}}
